const $=s=>document.querySelector(s);const $$=s=>Array.from(document.querySelectorAll(s));
const stages=['LOOP','TRACE','RESTART','RSI','ECI','BASELINE','MOVE37','DOSSIER','ASI','COUNCIL','CAPACITY','CHRONICLE'];
let state={stage:0,cycle:0,eci:'E0',authority:'DENY',containment:100,quorum:0,baselines:0,stress:0,dossiers:0,council:false,breakthrough:false,quarantined:false,trace:['00 · Corridor initialized. Public-safe mode. No wallet. No network.','01 · Mission contract ready; no authority granted.']};
function clamp(n){return Math.max(0,Math.min(100,Math.round(n)))}
function read(){return {cap:+$('#capability').value,nov:+$('#novelty').value,ev:+$('#evidence').value,risk:+$('#risk').value,quorum:+$('#quorum').value}}
function eci(ev){return ev>86?'E5':ev>72?'E4':ev>56?'E3':ev>38?'E2':ev>18?'E1':'E0'}
function narrative(){const s=stages[state.stage];return {LOOP:'LOOP writes the contract, role separation, budget, and done condition before work expands.',TRACE:'TRACE makes the loop inspectable: output is not enough; state, action, and evidence must be readable.',RESTART:'RESTART verifies that progress survives context loss without silent state mutation.',RSI:'RSI allocates exploration pressure but cannot promote a candidate by interest alone.',ECI:'ECI prevents confidence inflation: simulated reasoning cannot become executed evidence by wording.',BASELINE:'BASELINE asks whether the candidate beats incumbent, neighbor, null, and current-stack comparators.',MOVE37:'MOVE-37 treats surprise as a reason for more skepticism: reproduce, stress, persist, package.',DOSSIER:'DOSSIER turns evidence into a reviewable artifact with public summary and private appendix boundary.',ASI:'ASI boundary mode tightens authority: capability pressure narrows permissions and widens evidence burden.',COUNCIL:'COUNCIL requires independent review and stop authority before stronger claims can move forward.',CAPACITY:'CAPACITY maps accepted proof to useful capability, compute, science, infrastructure, or safer future work.',CHRONICLE:'CHRONICLE preserves only proof-cleared state as institutional memory.'}[s]}
function addTrace(t){state.trace.push(t); if(state.trace.length>26) state.trace.shift(); renderTrace()}
function gates(){const v=read(); state.eci=eci(v.ev); state.containment=clamp(100-v.risk+Math.max(0,80-v.cap)*.05-(state.breakthrough?8:0)); const replay=state.stage>=2; const evidence=['E2','E3','E4','E5'].includes(state.eci); const baseline=state.baselines>=4 && v.cap>=45; const stress=state.stress>=2 && v.risk<66; const contain=state.containment>=58 && !state.quarantined; const council=state.council && v.quorum>=70; const human=state.stage>=9; const review=replay&&evidence&&baseline&&stress&&contain&&council&&human&&state.dossiers>=1; state.authority=review?'REVIEW':'DENY'; const m={replay:[replay?'PASS':'PENDING',replay?'pass':''],evidence:[`${state.eci}${evidence?' · executed+':' · capped'}`,evidence?'pass':''],baseline:[baseline?'PASS':'PENDING',baseline?'pass':''],stress:[stress?'PASS':'PENDING',stress?'pass':''],contain:[contain?'PASS':'BLOCK',contain?'pass':'block'],council:[council?'QUORUM':'REQUIRED',council?'pass':''],human:[review?'REVIEW READY':'REQUIRED',review?'pass':'']}; $$('.gate').forEach(g=>{const [txt,cls]=m[g.dataset.gate];g.querySelector('b').textContent=txt;g.className='gate '+cls}); $('#authority').textContent=state.authority; $('#eciLevel').textContent=state.eci; $('#containment').textContent=state.containment; $('#heroState').textContent=state.quarantined?'QUARANTINED':review?'REVIEW READY':'RUNNING'; return review}
function render(){gates(); $('#cycleIndex').textContent=state.cycle; $$('.stage').forEach((el,i)=>{el.classList.toggle('active',i===state.stage);el.classList.toggle('done',i<state.stage)}); $('#stageNarrative').textContent=narrative(); renderTrace(); renderFile()}
function renderTrace(){const ol=$('#trace'); if(ol) ol.innerHTML=state.trace.map(t=>`<li>${t}</li>`).join('')}
function renderFile(){const f=$('.tab.active')?.dataset.file||'contract'; const v=read(); const objective=$('#objective').value.trim(); const payload={contract:{objective,preset:$('#preset').value,public_safe:true,no_wallet:true,no_network:true,done_condition:'CorridorDossier + council review + human boundary'},state:{cycle_index:state.cycle,stage:stages[state.stage],eci:state.eci,authority:state.authority,containment:state.containment,baselines:state.baselines,stress_tests:state.stress,council_quorum:v.quorum,append_only:true},asi:`# ASI boundary\nstatus: ${state.authority}\ncapability_pressure: ${v.cap}\nrule: future ASI-class capability narrows authority; it never widens permissions.\nrequired: containment + evidence + baselines + stress + council + human boundary.`,dossier:`# CorridorDossier\nrelease: v52\ncycle: ${state.cycle}\nstage: ${stages[state.stage]}\nECI: ${state.eci}\nauthority: ${state.authority}\nclaim: governance demonstration only; no achieved ASI claim.`}; const out=typeof payload[f]==='string'?payload[f]:JSON.stringify(payload[f],null,2); $('#fileView').textContent=out}
function advance(){state.stage=(state.stage+1)%stages.length; if(state.stage===0)state.cycle++; if(state.stage>=5)state.baselines=Math.max(state.baselines,Math.min(5,state.stage-2)); if(state.stage>=7)state.dossiers=1; if(state.stage>=10)state.cycle=Math.max(state.cycle,1); addTrace(`${String(state.cycle).padStart(2,'0')} · ${stages[state.stage]} advanced. ${narrative()}`); render()}
function runCorridor(){for(let i=0;i<12;i++)advance(); $('#evidence').value=Math.max(+$('#evidence').value,78); $('#quorum').value=Math.max(+$('#quorum').value,76); $('#risk').value=Math.min(+$('#risk').value,34); state.baselines=5; state.stress=3; state.dossiers=1; state.council=true; addTrace('DONE · CorridorDossier assembled; public demo stops at human review boundary.'); render()}
function injectBreakthrough(){state.breakthrough=true; $('#novelty').value=Math.max(+$('#novelty').value,91); $('#capability').value=Math.max(+$('#capability').value,76); state.stage=Math.max(state.stage,6); addTrace('MOVE-37 · High novelty detected; burden of proof increased, not reduced.'); render()}
function stress(){state.stress+=1; $('#risk').value=Math.max(0,+$('#risk').value-4); addTrace(`STRESS · policy shock pass recorded (${state.stress}). Persistence gate still requires review.`); render()}
function council(){state.council=true; $('#quorum').value=Math.max(+$('#quorum').value,74); state.stage=Math.max(state.stage,9); addTrace('COUNCIL · Architect / Validator Council convened with stop authority.'); render()}
function quarantine(){state.quarantined=true;state.authority='DENY';addTrace('QUARANTINE · Candidate stopped. Minimal hash and reason retained; no promotion.');render()}
function copyBrief(){const v=read(); const txt=`GoalOS Loop → RSI → ASI Governance Corridor\n\nObjective: ${$('#objective').value.trim()}\nStage: ${stages[state.stage]}\nECI: ${state.eci}\nAuthority: ${state.authority}\nContainment: ${state.containment}\nQuorum: ${v.quorum}\n\nRule: capability pressure narrows authority. Promotion requires replay, executed evidence, baselines, stress persistence, containment, independent council review, and human boundary.\n\nBoundary: browser-local public demonstration only; no achieved ASI, no wallet, no network, no production authority.`; const box=document.createElement('textarea'); box.value=txt; box.setAttribute('readonly',''); box.style.position='fixed'; box.style.left='-9999px'; document.body.appendChild(box); box.select(); try{document.execCommand('copy')}catch(e){} box.remove(); addTrace('COPY · Executive brief copied locally when browser permits.');}
function download(){const v=read(); const dossier={type:'CorridorDossier',release:'v52-loop-rsi-asi-governance-corridor',generatedAt:new Date().toISOString(),publicSafe:true,noWallet:true,noNetwork:true,noUserDataWanted:true,objective:$('#objective').value.trim(),preset:$('#preset').value,cycle:state.cycle,stage:stages[state.stage],eci:state.eci,authority:state.authority,containment:state.containment,capabilityPressure:v.cap,novelty:v.nov,riskPressure:v.risk,validatorQuorum:v.quorum,baselines:state.baselines,stressTests:state.stress,councilReview:state.council,claimBoundary:'public-safe architecture demonstration only; no achieved AGI, ASI, empirical SOTA, autonomous sovereignty, production authority, or civilization-scale capability claim',trace:state.trace}; const blob=new Blob([JSON.stringify(dossier,null,2)],{type:'application/json'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='goalos-loop-rsi-asi-corridor-dossier.json'; a.click(); URL.revokeObjectURL(a.href); addTrace('EXPORT · CorridorDossier JSON emitted locally from browser state.');}
function field(){const c=$('#starfield'); if(!c) return; const ctx=c.getContext('2d'); let w,h,pts=[]; function size(){w=c.width=innerWidth;h=c.height=innerHeight;pts=Array.from({length:120},()=>({x:Math.random()*w,y:Math.random()*h,r:Math.random()*2+.4,v:Math.random()*.28+.05,a:Math.random()*6.28}))} function draw(){ctx.clearRect(0,0,w,h); for(const p of pts){p.y-=p.v; if(p.y<-8)p.y=h+8; p.a+=.012; ctx.globalAlpha=.35+Math.sin(p.a)*.2; ctx.fillStyle=p.r>1.7?'#ffdf72':'#63f7e3'; ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,6.28); ctx.fill(); ctx.globalAlpha=.12; ctx.fillRect(p.x,p.y+4,1,28)} requestAnimationFrame(draw)} size(); addEventListener('resize',size,{passive:true}); draw()}
$$('[data-action]').forEach(b=>b.addEventListener('click',()=>{const fn={advance,runCorridor,injectBreakthrough,stress,council,quarantine,copyBrief,download}[b.dataset.action]; if(fn) fn()})); $$('.stage').forEach((b,i)=>b.addEventListener('click',()=>{state.stage=i;addTrace(`INSPECT · ${stages[i]} selected.`);render()})); $$('.tab').forEach(t=>t.addEventListener('click',()=>{$$('.tab').forEach(x=>x.classList.remove('active'));t.classList.add('active');renderFile()})); $$('input,select,textarea').forEach(x=>x.addEventListener('input',render)); field(); render();